const item = $input.first().json; const body = item.body || item; const inner = body.body || {}; 
let rawParts = [body.text, body.caption, inner.text, inner.body, body.text?.body, body.text?.text].filter(t => typeof t === 'string' && t.trim().length > 0).map(p => p.trim());
// Aggressive Dedup (Remove substrings)
rawParts.sort((a, b) => b.length - a.length);
let uniqueParts = [];
for (const p of rawParts) {
  if (!uniqueParts.some(up => up.includes(p))) uniqueParts.push(p);
}
let uniqueText = uniqueParts.join('\n\n');
const isJunk = uniqueText.length < 70 || /sticker|audio|voice|gif/i.test(uniqueText);
return { ...item, platform: "WhatsApp", sender_contact: body.from || "Unknown", texto_limpio: uniqueText, looksValuable: !isJunk };

